import React, { useState } from 'react';

const PatientDashboard = ({ patient, onLogout }) => {
  const [activeTab, setActiveTab] = useState('queue');
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [paymentProcessing, setPaymentProcessing] = useState(false);
  const [inQueue, setInQueue] = useState(false);
  const [paymentSuccess, setPaymentSuccess] = useState(false);
  const [prescriptions, setPrescriptions] = useState([]);
  const [labTests, setLabTests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchPatientData();
  }, []);

  const fetchPatientData = async () => {
    try {
      const token = localStorage.getItem('token');
      const patientId = patient?.id || patient?.patientId;
      
      // Fetch prescriptions
      const prescriptionsResponse = await fetch(`http://localhost:5000/api/prescriptions/patient/${patientId}`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      if (prescriptionsResponse.ok) {
        const prescriptionsData = await prescriptionsResponse.json();
        setPrescriptions(prescriptionsData);
      }
      
      // Fetch lab tests
      const labTestsResponse = await fetch(`http://localhost:5000/api/lab-tests/patient/${patientId}`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      if (labTestsResponse.ok) {
        const labTestsData = await labTestsResponse.json();
        setLabTests(labTestsData);
      }
      
      setLoading(false);
    } catch (error) {
      console.error('Error fetching patient data:', error);
      setLoading(false);
    }
  };

  // Mock data - replace with actual API calls
  const queueData = {
    patientId: patient?.patientId || 'P-2023-0425',
    queueNumber: 4,
    patientsAhead: 3,
    estimatedTime: '11:44 PM',
    status: 'Waiting',
    queueList: [
      { queueNumber: 1, patientId: 'P-2023-0421', status: 'In Consultation', time: 'Currently' },
      { queueNumber: 2, patientId: 'P-2023-0422', status: 'Waiting', time: '11:24 PM' },
      { queueNumber: 3, patientId: 'P-2023-0423', status: 'Waiting', time: '11:34 PM' },
      { queueNumber: 4, patientId: 'P-2023-0425', status: 'Waiting', time: '11:44 PM', isYou: true },
    ]
  };

  const appointments = [
    { id: 1, doctor: 'Dr. Abebe Tadesse', date: '2024-03-15', time: '10:00 AM', status: 'Confirmed' },
    { id: 2, doctor: 'Dr. Marta Bekele', date: '2024-03-20', time: '2:30 PM', status: 'Pending' },
  ];

  const handleJoinQueue = () => {
    setShowPaymentModal(true);
  };

  const handlePayment = async (paymentMethod) => {
    setPaymentProcessing(true);
    
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/queue/join', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          patientId: patient?.id || patient?.patientId,
          paymentMethod: paymentMethod,
          amount: 500 // Consultation fee in ETB
        }),
      });

      const data = await response.json();

      if (response.ok) {
        setPaymentSuccess(true);
        setInQueue(true);
        setTimeout(() => {
          setShowPaymentModal(false);
          setPaymentSuccess(false);
          // Refresh queue data
          window.location.reload();
        }, 2000);
      } else {
        alert('Payment failed: ' + data.message);
      }
    } catch (error) {
      alert('Network error. Please try again.');
    } finally {
      setPaymentProcessing(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex">
      {/* Payment Modal */}
      {showPaymentModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full p-8">
            {paymentSuccess ? (
              <div className="text-center">
                <div className="w-20 h-20 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-4">
                  <span className="text-4xl text-white">✓</span>
                </div>
                <h3 className="text-2xl font-bold text-gray-900 mb-2">Payment Successful!</h3>
                <p className="text-gray-600">You have been added to the queue.</p>
              </div>
            ) : (
              <>
                <h3 className="text-2xl font-bold text-gray-900 mb-4">Payment Required</h3>
                <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 mb-6">
                  <p className="text-sm text-gray-600 mb-1">Consultation Fee:</p>
                  <p className="text-3xl font-bold text-blue-600">ETB 500</p>
                </div>
                
                <p className="text-gray-600 mb-6">Select your payment method:</p>
                
                <div className="space-y-3">
                  <button
                    onClick={() => handlePayment('card')}
                    disabled={paymentProcessing}
                    className="w-full flex items-center justify-between px-6 py-4 border-2 border-blue-500 rounded-lg hover:bg-blue-50 transition-colors"
                  >
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl">💳</span>
                      <span className="font-semibold text-gray-900">Credit/Debit Card</span>
                    </div>
                    <span className="text-blue-600">→</span>
                  </button>
                  
                  <button
                    onClick={() => handlePayment('mobile')}
                    disabled={paymentProcessing}
                    className="w-full flex items-center justify-between px-6 py-4 border-2 border-green-500 rounded-lg hover:bg-green-50 transition-colors"
                  >
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl">📱</span>
                      <span className="font-semibold text-gray-900">Mobile Money</span>
                    </div>
                    <span className="text-green-600">→</span>
                  </button>
                  
                  <button
                    onClick={() => handlePayment('cash')}
                    disabled={paymentProcessing}
                    className="w-full flex items-center justify-between px-6 py-4 border-2 border-yellow-500 rounded-lg hover:bg-yellow-50 transition-colors"
                  >
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl">💵</span>
                      <span className="font-semibold text-gray-900">Cash at Reception</span>
                    </div>
                    <span className="text-yellow-600">→</span>
                  </button>
                </div>
                
                <button
                  onClick={() => setShowPaymentModal(false)}
                  disabled={paymentProcessing}
                  className="w-full mt-6 px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  Cancel
                </button>
                
                {paymentProcessing && (
                  <div className="mt-4 text-center">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500 mx-auto"></div>
                    <p className="text-sm text-gray-600 mt-2">Processing payment...</p>
                  </div>
                )}
              </>
            )}
          </div>
        </div>
      )}

      {/* Sidebar */}
      <div className="w-64 bg-slate-800 text-white min-h-screen">
        <div className="p-6">
          <div className="flex items-center space-x-2 mb-2">
            <div className="w-10 h-10 bg-gradient-to-br from-green-400 to-blue-500 rounded-lg flex items-center justify-center">
              <span className="text-white text-xl">🏥</span>
            </div>
            <div>
              <h1 className="text-xl font-bold">Patient</h1>
              <h2 className="text-lg font-semibold">Management</h2>
            </div>
          </div>
        </div>

        <nav className="mt-8">
          <button
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'dashboard'
                ? 'bg-slate-700 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">📊</span>
            Dashboard
          </button>
          
          <button
            onClick={() => setActiveTab('queue')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'queue'
                ? 'bg-blue-600 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">🚶‍♂️</span>
            Queue
          </button>
          
          <button
            onClick={() => setActiveTab('prescriptions')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'prescriptions'
                ? 'bg-slate-700 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">💊</span>
            Prescriptions
          </button>
          
          <button
            onClick={() => setActiveTab('labresults')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'labresults'
                ? 'bg-slate-700 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">🔬</span>
            Lab Results
          </button>
          
          <button
            onClick={() => setActiveTab('appointment')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'appointment'
                ? 'bg-slate-700 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">📅</span>
            Appointment
          </button>
          
          <button
            onClick={() => setActiveTab('portfolio')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'portfolio'
                ? 'bg-slate-700 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">📋</span>
            Portfolio
          </button>
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col">
        {/* Header */}
        <header className="bg-white shadow-sm">
          <div className="px-8 py-4 flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold text-gray-900">
                {activeTab === 'queue' && 'Your Queue Status'}
                {activeTab === 'dashboard' && 'Patient Dashboard'}
                {activeTab === 'prescriptions' && 'My Prescriptions'}
                {activeTab === 'labresults' && 'My Lab Results'}
                {activeTab === 'appointment' && 'My Appointments'}
                {activeTab === 'portfolio' && 'Medical Portfolio'}
              </h2>
              <p className="text-sm text-gray-500">
                {activeTab === 'queue' && 'Showing patients ahead of you in the queue'}
                {activeTab === 'prescriptions' && 'View your prescriptions and medication history'}
                {activeTab === 'labresults' && 'View your laboratory test results'}
              </p>
            </div>

            <div className="flex items-center space-x-4">
              <div className="text-right">
                <p className="text-sm font-medium text-gray-900">Patient Molla</p>
                <p className="text-xs text-gray-500">ID: {queueData.patientId}</p>
              </div>
              <div className="w-12 h-12 bg-gradient-to-br from-blue-400 to-blue-600 rounded-full flex items-center justify-center text-white font-bold text-lg">
                M
              </div>
              <button
                onClick={onLogout}
                className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors"
              >
                Logout
              </button>
            </div>
          </div>
        </header>

        {/* Content Area */}
        <main className="flex-1 p-8 overflow-auto">
          {activeTab === 'queue' && (
            <div className="max-w-5xl">
              {/* Join Queue Button */}
              {!inQueue && (
                <div className="bg-gradient-to-r from-blue-500 to-blue-600 rounded-xl shadow-lg p-6 mb-8 text-white">
                  <div className="flex items-center justify-between">
                    <div>
                      <h3 className="text-2xl font-bold mb-2">Ready to see a doctor?</h3>
                      <p className="text-blue-100">Join the queue now and get your queue number</p>
                    </div>
                    <button
                      onClick={handleJoinQueue}
                      className="px-8 py-4 bg-white text-blue-600 rounded-lg hover:bg-blue-50 transition-all transform hover:scale-105 font-bold text-lg shadow-lg"
                    >
                      Join Queue Now
                    </button>
                  </div>
                </div>
              )}

              {/* Queue Status Card */}
              <div className="bg-white rounded-xl shadow-lg p-8 mb-8">
                <div className="flex items-center space-x-4 mb-6">
                  <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center">
                    <span className="text-3xl">👥</span>
                  </div>
                  <div>
                    <h3 className="text-2xl font-bold text-gray-900">Patients Ahead of You</h3>
                    <p className="text-gray-600">{queueData.patientsAhead} patients are ahead of you in the queue</p>
                  </div>
                </div>

                {/* Queue Table */}
                <div className="overflow-hidden rounded-lg border border-gray-200">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Queue #
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Patient ID
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Status
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Estimated Time
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {queueData.queueList.map((item) => (
                        <tr
                          key={item.queueNumber}
                          className={item.isYou ? 'bg-blue-50 border-l-4 border-blue-500' : ''}
                        >
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-bold ${
                              item.isYou ? 'bg-green-500' : 'bg-blue-500'
                            }`}>
                              {item.queueNumber}
                            </div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="flex items-center">
                              <span className="text-sm font-medium text-gray-900">{item.patientId}</span>
                              {item.isYou && (
                                <span className="ml-2 px-3 py-1 bg-blue-500 text-white text-xs font-semibold rounded-full">
                                  YOU
                                </span>
                              )}
                            </div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className={`px-3 py-1 inline-flex text-xs leading-5 font-semibold rounded-full ${
                              item.status === 'In Consultation'
                                ? 'bg-green-100 text-green-800'
                                : 'bg-yellow-100 text-yellow-800'
                            }`}>
                              {item.status}
                            </span>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                            {item.time}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              {/* Info Cards */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl shadow-lg p-6 text-white">
                  <div className="text-4xl mb-2">🎫</div>
                  <p className="text-sm opacity-90 mb-1">Your Queue Number</p>
                  <p className="text-3xl font-bold">{queueData.queueNumber}</p>
                </div>

                <div className="bg-gradient-to-br from-green-500 to-green-600 rounded-xl shadow-lg p-6 text-white">
                  <div className="text-4xl mb-2">👥</div>
                  <p className="text-sm opacity-90 mb-1">Patients Ahead</p>
                  <p className="text-3xl font-bold">{queueData.patientsAhead}</p>
                </div>

                <div className="bg-gradient-to-br from-purple-500 to-purple-600 rounded-xl shadow-lg p-6 text-white">
                  <div className="text-4xl mb-2">⏰</div>
                  <p className="text-sm opacity-90 mb-1">Estimated Time</p>
                  <p className="text-3xl font-bold">{queueData.estimatedTime}</p>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'appointment' && (
            <div className="max-w-5xl">
              <div className="bg-white rounded-xl shadow-lg p-8">
                <h3 className="text-2xl font-bold text-gray-900 mb-6">My Appointments</h3>
                <div className="space-y-4">
                  {appointments.map((apt) => (
                    <div key={apt.id} className="border border-gray-200 rounded-lg p-6 hover:shadow-md transition-shadow">
                      <div className="flex justify-between items-center">
                        <div>
                          <h4 className="text-lg font-semibold text-gray-900">{apt.doctor}</h4>
                          <p className="text-gray-600">{apt.date} at {apt.time}</p>
                        </div>
                        <span className={`px-4 py-2 rounded-full text-sm font-semibold ${
                          apt.status === 'Confirmed'
                            ? 'bg-green-100 text-green-800'
                            : 'bg-yellow-100 text-yellow-800'
                        }`}>
                          {apt.status}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'dashboard' && (
            <div className="max-w-5xl">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
                <div className="bg-white rounded-xl shadow-lg p-6">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-semibold text-gray-900">Appointments</h3>
                    <span className="text-3xl">📅</span>
                  </div>
                  <p className="text-3xl font-bold text-blue-600">{appointments.length}</p>
                  <p className="text-sm text-gray-500 mt-2">Upcoming appointments</p>
                </div>

                <div className="bg-white rounded-xl shadow-lg p-6">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-semibold text-gray-900">Queue Position</h3>
                    <span className="text-3xl">🎫</span>
                  </div>
                  <p className="text-3xl font-bold text-green-600">#{queueData.queueNumber}</p>
                  <p className="text-sm text-gray-500 mt-2">Current position</p>
                </div>

                <div className="bg-white rounded-xl shadow-lg p-6">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-semibold text-gray-900">Medical Records</h3>
                    <span className="text-3xl">📋</span>
                  </div>
                  <p className="text-3xl font-bold text-purple-600">12</p>
                  <p className="text-sm text-gray-500 mt-2">Total records</p>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default PatientDashboard;
